import {
  MARKER_CONTENT_TO_BORDER_PADDING,
  MARKER_STROKE_WIDTH,
} from '../../../../../constants.js';
import { CANVAS_PIXEL_OFFSET } from '../../../constants.js';
import { VALUE_MARKER_WIDTH } from '../constants.js';
import { ValueMarkerPointerPosition } from '../types.js';

export const calculateCenteredText = (
  x: number,
  width: number,
  orientation: ValueMarkerPointerPosition,
  contentWidth: number,
) => {
  const isDefaultMarker = width === VALUE_MARKER_WIDTH;
  const diff = (width - contentWidth) / 2;
  let xOffset = x - CANVAS_PIXEL_OFFSET;

  switch (orientation) {
    case 'right': {
      xOffset = isDefaultMarker
        ? x - diff - MARKER_STROKE_WIDTH
        : x - MARKER_CONTENT_TO_BORDER_PADDING;
      break;
    }
    case 'left': {
      xOffset = isDefaultMarker
        ? x + diff - CANVAS_PIXEL_OFFSET
        : x + MARKER_CONTENT_TO_BORDER_PADDING;

      break;
    }
  }

  return xOffset;
};
